import React, { useEffect, useState } from 'react';
import { useTrail, animated } from '@react-spring/web';
import Icon from './Icon';
import icons from '../config/iconContacts';

interface ContactsProps {
  toggle: boolean;
}

const CLOSE_UNMOUNT_MS = 950;

const Contacts = ({ toggle }: ContactsProps) => {
  const contactsTrail = useTrail(icons.length, {
    from: { x: 150 },
    to: { x: toggle ? 0 : 150 },
    config: { tension: 305, friction: 19, mass: 0.58 },
    trail: 48,
    delay: toggle ? 210 : 0,
  });

  const [display, setDisplay] = useState(false);

  useEffect(() => {
    if (toggle && !display) {
      setDisplay(true);
    }
    if (!toggle && display) {
      const t = setTimeout(() => {
        setDisplay(false);
      }, CLOSE_UNMOUNT_MS);
      return () => clearTimeout(t);
    }
  }, [toggle, display]);

  return (
    <div className="relative -right-[110px] top-0 flex h-[100px] w-[230px] items-center justify-between p-[5px] max-[750px]:-right-10 max-[750px]:top-[-15px] max-[750px]:h-[50px] max-[750px]:w-[150px]">
      {display &&
        contactsTrail.map((styles, index) => (
          <animated.div
            key={index}
            style={{
              transform: styles.x.to((x: number) => `translateX(${x}px)`),
              willChange: 'transform',
            }}
          >
            <Icon
              name={icons[index].name}
              title={icons[index].title}
              url={icons[index].url}
            />
          </animated.div>
        ))}
    </div>
  );
};

export default Contacts;
